import{_ as o,c as i,o as r,a as e,b as a}from"./app.426dd711.js";const z=JSON.parse('{"title":"Refactorizaci\xF3n (Refactoring)","description":"","frontmatter":{},"headers":[],"relativePath":"practices/refactoring.md"}'),n={name:"practices/refactoring.md"},c=e("h1",{id:"refactorizacion-refactoring",tabindex:"-1"},[a("Refactorizaci\xF3n "),e("em",null,"(Refactoring)"),a(),e("a",{class:"header-anchor",href:"#refactorizacion-refactoring","aria-hidden":"true"},"#")],-1),s=e("blockquote",null,[e("p",null,"Un mayor n\xFAmero de l\xEDneas de c\xF3digo no siempre es mejor, y adem\xE1s requiere mayor esfuerzo de pruebas y de mantenimiento. La refactorizaci\xF3n es una t\xE9cnica que consiste en minimizar el c\xF3digo fuente de un software sin afectar a su comportamiento externo.")],-1),t=e("p",null,"Dado que se propone \u201Cdesarrollar lo m\xEDnimamente indispensable\u201D, en la construcci\xF3n de cada nueva funcionalidad, puede (y debe) ser necesario, realizar una refactorizaci\xF3n del c\xF3digo, a fin de lograr una mayor cohesi\xF3n de \xE9ste, impidiendo redundancias. Cuando tenemos que introducir una nueva caracter\xEDstica del sistema, si esta tiene mucho en com\xFAn con otra previa, lo mejor es eliminar el c\xF3digo duplicado, sin miedo a que falle, debido a que con las pruebas continuas se corrobor\xE1 el correcto funcionamiento.",-1),d=e("p",null,"Seg\xFAn la refactorizaci\xF3n el c\xF3digo debe ser simple y claro. Esto provoca el huir del c\xF3digo duplicado. El c\xF3digo duplicado complica la tarea de programaci\xF3n por diversas causas. Una de ellas es que \u201Censucia\u201D el programa haci\xE9ndolo mas largo de lo estrictamente necesario (con lo que no satisfacemos el fundamento de los Dise\xF1os Simples). Adem\xE1s aumentan las posibilidades de tener errores, y hace incomprensible o de dif\xEDcil lectura el programa. Por ello, la refactorizaci\xF3n es la principal t\xE9cnica propuesta, para evolucionar el c\xF3digo de la aplicaci\xF3n con facilidad en cada iteraci\xF3n.",-1),l=[c,s,t,d];function u(m,p,f,g,_,h){return r(),i("div",null,l)}const q=o(n,[["render",u]]);export{z as __pageData,q as default};
